# Set creation and element checks
s = {1, 2, 3, 3, 3}
print(s)            # {1, 2, 3}
s.add(4)
s.remove(2)
s.discard(10)       # safe discard (no error if missing)
print(s)            # {1, 3, 4}

# Set Operations
a = {1, 2, 3}
b = {3, 4, 5}
union = a | b
print(union)         # {1, 2, 3, 4, 5}
intersection = a & b
print(intersection)  # {3}
difference = a - b
print(difference)    # {1, 2}
sym_diff = a ^ b
print(sym_diff)      # {1, 2, 4, 5}

# Set Comprehension
uniq_evens = {x**2 for x in range(5) if x % 2 == 0}
print(uniq_evens)    # {0, 16, 4}

# Dict creation & safe access
d = {"name": "Alice", "age": 30}
name = d["name"]
print(name)                # "Alice"
city = d.get("city", "N/A")
print(city)                # "N/A"

# Updates & insertions
d["city"] = "NYC"
d.update({"age": 31, "job": "dev"})
print(d)                   # {'name': 'Alice', 'age': 31, 'city': 'NYC', 'job': 'dev'}

# Deletions
del d["age"]
popped_value = d.pop("job")
print(popped_value)        # "dev"
print(d)                   # {'name': 'Alice', 'city': 'NYC'}

# Iteration Methods
for key in d:
    print(key, d[key])
for key, val in d.items():
    print(key, val)

# Dict Comprehension
squares = {x: x**2 for x in range(5)}
print(squares)             # {0: 0, 1: 1, 2: 4, 3: 9, 4: 16}

# Merge Operator (Python 3.9+)
merged = {"a": 1} | {"b": 2}
print(merged)              # {"a": 1, "b": 2}
